CREATE CACHED TABLE IF NOT EXISTS "SCRIPTS_FAILURE" (
    "CREATETIMESTAMP" TIMESTAMP NULL,
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "SCRIPTNAME" VARCHAR(4096) NOT NULL,
    "SCRIPTTYPE" VARCHAR(1024) NOT NULL,
    "MESSAGE" VARCHAR(8388608) NOT NULL,
);


CREATE CACHED TABLE IF NOT EXISTS "SCRIPTS_FAILURE_SCREENSHOT" (
    "CREATETIMESTAMP" TIMESTAMP NULL,
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "FAILUREID" BIGINT NOT NULL,
    "DATA" VARCHAR(8388608) NOT NULL,
);

CREATE INDEX "SCRIPTS_FAILURE_SCREENSHOT_FAILUREID_IDX" ON "SCRIPTS_FAILURE_SCREENSHOT" ("FAILUREID");
